import React, { useState } from "react";
import { Outlet, useNavigate, useLocation } from "react-router-dom";
import {
  Box,
  Drawer,
  List,
  ListItem,
  ListItemButton,
  ListItemIcon,
  ListItemText,
  IconButton,
  Typography,
  AppBar,
  Toolbar,
  Divider,
} from "@mui/material";
import {
  Menu as MenuIcon,
  Repeat as TransactionsIcon,
  Filter as BrowseIcon,
  AccountBalance as AccountsIcon,
  People as PeoplesIcon,
  Apps as CategoriesIcon,
  Layers as SplitGroupsIcon,
  SwapHoriz as SelfTransfersIcon,
  Logout as LogoutIcon,
  Close as CloseIcon,
} from "@mui/icons-material";
import { useAuth } from "../contexts/AuthContext";
import { logout } from "../services/auth";

const DRAWER_WIDTH = 280;

const navItems = [
  {
    key: "transactions",
    label: "Transactions",
    icon: TransactionsIcon,
    path: "/transactions",
  },
  {
    key: "browse",
    label: "Browse",
    icon: BrowseIcon,
    path: "/transactions/browse",
  },
  { key: "accounts", label: "Accounts", icon: AccountsIcon, path: "/accounts" },
  { key: "peoples", label: "People", icon: PeoplesIcon, path: "/peoples" },
  {
    key: "categories",
    label: "Categories",
    icon: CategoriesIcon,
    path: "/categories",
  },
  {
    key: "split-groups",
    label: "Split groups",
    icon: SplitGroupsIcon,
    path: "/split-groups",
  },
  {
    key: "self-transfers",
    label: "Self transfers",
    icon: SelfTransfersIcon,
    path: "/self-transfers",
  },
];

export default function MainLayout() {
  const navigate = useNavigate();
  const location = useLocation();
  const { setAccessToken } = useAuth();
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);

  async function onLogout() {
    await logout();
    setAccessToken(null);
    setIsDrawerOpen(false);
  }

  function handleNavigation(path: string) {
    navigate(path);
    setIsDrawerOpen(false);
  }

  const drawer = (
    <Box sx={{ height: "100%", display: "flex", flexDirection: "column" }}>
      <Box
        sx={{
          p: 2,
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
        }}
      >
        <Typography variant="h6" sx={{ fontWeight: 600 }}>
          Navigation
        </Typography>
        <IconButton onClick={() => setIsDrawerOpen(false)} size="small">
          <CloseIcon />
        </IconButton>
      </Box>

      <Divider />

      <List sx={{ flex: 1, py: 1 }}>
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive =
            location.pathname === item.path ||
            (item.key === "transactions" &&
              location.pathname.startsWith("/transactions") &&
              location.pathname !== "/transactions/browse");

          return (
            <ListItem key={item.key} disablePadding sx={{ px: 1 }}>
              <ListItemButton
                onClick={() => handleNavigation(item.path)}
                selected={isActive}
                sx={{
                  borderRadius: 2,
                  "&.Mui-selected": {
                    bgcolor: "action.selected",
                    "&:hover": {
                      bgcolor: "action.selected",
                    },
                  },
                }}
              >
                <ListItemIcon sx={{ minWidth: 40 }}>
                  <Icon fontSize="small" />
                </ListItemIcon>
                <ListItemText
                  primary={item.label}
                  primaryTypographyProps={{
                    fontSize: "0.875rem",
                    fontWeight: isActive ? 600 : 400,
                  }}
                />
              </ListItemButton>
            </ListItem>
          );
        })}
      </List>

      <Divider />

      <Box sx={{ p: 1 }}>
        <ListItemButton
          onClick={onLogout}
          sx={{
            borderRadius: 2,
            color: "error.main",
            "&:hover": {
              bgcolor: "error.light",
              color: "error.contrastText",
            },
          }}
        >
          <ListItemIcon sx={{ minWidth: 40, color: "inherit" }}>
            <LogoutIcon fontSize="small" />
          </ListItemIcon>
          <ListItemText
            primary="Logout"
            primaryTypographyProps={{
              fontSize: "0.875rem",
              fontWeight: 600,
            }}
          />
        </ListItemButton>
      </Box>
    </Box>
  );

  return (
    <Box sx={{ display: "flex", height: "100vh" }}>
      <AppBar
        position="fixed"
        sx={{
          width: { sm: `calc(100% - ${DRAWER_WIDTH}px)` },
          ml: { sm: `${DRAWER_WIDTH}px` },
          bgcolor: "background.paper",
          color: "text.primary",
          boxShadow: 1,
          borderBottom: "1px solid",
          borderColor: "divider",
        }}
      >
        <Toolbar>
          <IconButton
            color="inherit"
            aria-label="open drawer"
            edge="start"
            onClick={() => setIsDrawerOpen(true)}
            sx={{ mr: 2, display: { sm: "none" } }}
          >
            <MenuIcon />
          </IconButton>
          <Typography
            variant="h6"
            noWrap
            component="div"
            sx={{ fontWeight: 600 }}
          >
            SplitApp
          </Typography>
        </Toolbar>
      </AppBar>

      <Box
        component="nav"
        sx={{ width: { sm: DRAWER_WIDTH }, flexShrink: { sm: 0 } }}
      >
        <Drawer
          variant="temporary"
          open={isDrawerOpen}
          onClose={() => setIsDrawerOpen(false)}
          ModalProps={{
            keepMounted: true,
          }}
          sx={{
            display: { xs: "block", sm: "none" },
            "& .MuiDrawer-paper": {
              boxSizing: "border-box",
              width: DRAWER_WIDTH,
            },
          }}
        >
          {drawer}
        </Drawer>
        <Drawer
          variant="permanent"
          sx={{
            display: { xs: "none", sm: "block" },
            "& .MuiDrawer-paper": {
              boxSizing: "border-box",
              width: DRAWER_WIDTH,
              borderRight: "1px solid",
              borderColor: "divider",
            },
          }}
          open
        >
          {drawer}
        </Drawer>
      </Box>

      <Box
        component="main"
        sx={{
          flexGrow: 1,
          width: { sm: `calc(100% - ${DRAWER_WIDTH}px)` },
          overflow: "auto",
          bgcolor: "background.default",
        }}
      >
        <Toolbar />
        <Outlet />
      </Box>
    </Box>
  );
}
